1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Step {
8	  type: string;
9	  items: Item[];
10	}
11	
12	interface Scenario {
13	  steps: Step[];
14	}
15	
16	const PROCESSING_FEE = 5;
17	const FIRST_INSURANCE_RATE = 0.1;
18	
19	const BASE_PREMIUM: Record<string, number> = {
20	  sword: 100,
21	  amulet: 60,
22	  staff: 80,
23	  potion: 40,
24	  rune: 25,
25	  moonstone: 25,
26	};
27	
28	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
29	const BLOCK_SIZE = 3;
30	const BLOCK_PREMIUM = 60;
31	const CURSE_SURCHARGE_RATE = 0.5;
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	
35	function calculateBasePremium(items: Item[]): number {
36	  const typeCounts: Record<string, number> = {};
37	  for (const item of items) {
38	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
39	  }
40	
41	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
42	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
43	      ? BLOCK_PREMIUM
44	      : count * BASE_PREMIUM[type];
45	    return total + premium;
46	  }, 0);
47	}
48	
49	function calculateItemSurcharges(items: Item[]): number {
50	  return items.reduce((total, item) => {
51	    const curseSurcharge = item.cursed ? BASE_PREMIUM[item.type] * CURSE_SURCHARGE_RATE : 0;
52	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
53	      ? BASE_PREMIUM[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE
54	      : 0;
55	    return total + curseSurcharge + enchantmentSurcharge;
56	  }, 0);
57	}
58	
59	export function processScenario(scenario: Scenario): unknown {
60	  const items = scenario.steps[0].items;
61	  const basePremium = calculateBasePremium(items);
62	  const itemSurcharges = calculateItemSurcharges(items);
63	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
64	  const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance + PROCESSING_FEE);
65	
66	  return [{ premium }];
67	}
